// Copyright 2018 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.package inspector// This file defines  typeOf(ast.Node) uint64.//// The initial map-based implementation was too slow;// see https://go-review.googlesource.com/c/tools/+/135655/1/go/ast/inspector/inspector.go#196import ("go/ast""math""golang.org/x/tools/internal/typeparams")const (nArrayType = )// typeOf returns a distinct single-bit value that represents the type of n.//// Various implementations were benchmarked with BenchmarkNewInspector:////GOGC=off//- type switch4.9-5.5ms2.1ms//- binary search over a sorted list of types5.5-5.9ms2.5ms//- linear scan, frequency-ordered list5.9-6.1ms2.7ms//- linear scan, unordered list6.4ms2.7ms//- hash table6.5ms3.1ms//// A perfect hash seemed like overkill.//// The compiler's switch statement is the clear winners it produces a binary tree in code,// with constant conditions and good branch prediction.// (Sadly it is the most verbose in source code.)// Binary search suffered from poor branch prediction. typeOf(n ast.Node) uint64 {// Fast path: nearly half of all nodes are identifiers.if _, ok := n.(*ast.Ident); ok {return 1 << nIdent}// These cases include all nodes encountered by ast.Inspect.switch n.(type) {case *ast.ArrayType:return 1 << nArrayTypecase *ast.AssignStmt:return 1 << nAssignStmtcase *ast.BadDecl:return 1 << nBadDeclcase *ast.BadExpr:return 1 << nBadExprcase *ast.BadStmt:return 1 << nBadStmtcase *ast.BasicLit:return 1 << nBasicLitcase *ast.BinaryExpr:return 1 << nBinaryExprcase *ast.BlockStmt:return 1 << nBlockStmtcase *ast.BranchStmt:return 1 << nBranchStmtcase *ast.CallExpr:return 1 << nCallExprcase *ast.CaseClause:return 1 << nCaseClausecase *ast.ChanType:return 1 << nChanTypecase *ast.CommClause:return 1 << nCommClausecase *ast.Comment:return 1 << nCommentcase *ast.CommentGroup:return 1 << nCommentGroupcase *ast.CompositeLit:return 1 << nCompositeLitcase *ast.DeclStmt:return 1 << nDeclStmtcase *ast.DeferStmt:return 1 << nDeferStmtcase *ast.Ellipsis:return 1 << nEllipsiscase *ast.EmptyStmt:return 1 << nEmptyStmtcase *ast.ExprStmt:return 1 << nExprStmtcase *ast.Field:return 1 << nFieldcase *ast.FieldList:return 1 FieldListcase *ast.Filereturn 1 Filecase *ast.ForSreturn 1 ForStmtcase *ast.Decl:return 1 << nDeclcase *ast.Lit:return 1 << nLitcase *ast.Type:return 1 << nTypecase *ast.GenDecl:return 1 << nGenDeclcase *ast.GoStmt:return 1 << nGoStmtcase *ast.Ident:return 1 << nIdentcase *ast.IfStmt:return 1 << nIfStmtcase *ast.ImportSpec:return 1 << nImportSpeccase *ast.IncDecStmt:return 1 << nIncDecStmtcase *ast.IndexExpr:return 1 << nIndexExprcase *typeparams.IndexListExpr:return 1 << nIndexListExprcase *ast.InterfaceType:return 1 << nInterfaceTypecase *ast.KeyValueExpr:return 1 << nKeyValueExprcase *ast.LabeledStmt:return 1 << nLabeledStmtcase *ast.MapType:return 1 << nMapTypecase *ast.Package:return 1 << nPackagecase *ast.ParenExpr:return 1 << nParenExprcase *ast.RangeStmt:return 1 << nRangeStmtcase *ast.ReturnStmt:return 1 << nReturnStmtcase *ast.SelectStmt:return 1 << nSelectStmtcase *ast.SelectorExpr:return 1 << nSelectorExprcase *ast.SendStmt:return 1 << nSendStmtcase *ast.SliceExpr:return 1 << nSliceExprcase *ast.StarExpr:return 1 << nStarExprcase *ast.StructType:return 1 << nStructTypecase *ast.SwitchStmt:return 1 << nSwitchStmtcase *ast.TypeAssertExpr:return 1 << nTypeAssertExprcase *ast.TypeSpec:turn 1 << nTypeSpeccase *ast.TypeSwitchStmt:return 1 << nTypeSwitchStmtcase *ast.UnaryExpr:return 1 << nUnaryExprcase *ast.ValueSpec:return 1 << nValueSpec}return 0} maskOf(nodes []ast.Node) uint64 {if nodes == nil {return math.MaxUint64 // match all node types}var mask uint64for _, n := range nodes {mask |= typeOf(n)}return mask}